7	
8	const BUILTIN_EXCLUDED_DIRS: &[&str] = &[
9	    ".git",
10	    "target",
11	    "node_modules",
12	    "__pycache__",
13	    "vendor",
14	    "dist",
15	    ".next",
16	];
