67	pub fn collect_all_functions(
68	    paths: &[String],
69	    exclude_set: &GlobSet,
70	) -> (Vec<FunctionInfo>, Vec<String>) {
71	    let mut functions: Vec<FunctionInfo> = Vec::new();
72	    let mut errors: Vec<String> = Vec::new();
73	    for path_str in paths {
74	        let path = Path::new(path_str);
75	        if !path.exists() {
76	            errors.push(format!("path does not exist: {}", path_str));
77	        } else {
78	            collect_functions_from_path(path, exclude_set, &mut functions, &mut errors);
79	        }
80	    }
81	    (functions, errors)
82	}
83	
84	pub fn collect_functions_from_path(
85	    path: &Path,
86	    exclude_set: &GlobSet,
87	    functions: &mut Vec<FunctionInfo>,
88	    errors: &mut Vec<String>,
89	) {
90	    if path.is_file() {
91	        collect_from_single_file(path, exclude_set, functions, errors);
92	    } else {
93	        collect_from_directory(path, exclude_set, functions, errors);
94	    }
95	}
96	
97	pub fn collect_from_single_file(
98	    path: &Path,
99	    exclude_set: &GlobSet,
100	    functions: &mut Vec<FunctionInfo>,
101	    errors: &mut Vec<String>,
102	) {
103	    if should_scan_file(path, exclude_set) {
104	        process_file(path, functions, errors);
105	    }
106	}
107	
108	fn should_scan_file(path: &Path, exclude_set: &GlobSet) -> bool {
109	    !is_builtin_excluded(path)
110	        && is_rust_file(path)
111	        && !should_skip(path, exclude_set)
112	        && !is_git_ignored(path)
113	}
114	
115	fn process_entry(
116	    entry: Result<walkdir::DirEntry, walkdir::Error>,
117	    exclude_set: &GlobSet,
118	    functions: &mut Vec<FunctionInfo>,
119	    errors: &mut Vec<String>,
120	) {
121	    match entry {
122	        Ok(e) if e.file_type().is_file() && should_scan_file(e.path(), exclude_set) => {
123	            process_file(e.path(), functions, errors);
124	        }
125	        Ok(_) => {}
126	        Err(err) => errors.push(format!("walk error: {}", err)),
127	    }
128	}
129	
130	pub fn collect_from_directory(
131	    path: &Path,
132	    exclude_set: &GlobSet,
133	    functions: &mut Vec<FunctionInfo>,
134	    errors: &mut Vec<String>,
135	) {
136	    let walker = WalkDir::new(path)
137	        .sort_by_file_name()
138	        .into_iter()
139	        .filter_entry(|e| !e.file_type().is_dir() || !is_builtin_excluded(e.path()));
140	    for entry in walker {
141	        process_entry(entry, exclude_set, functions, errors);
142	    }
143	}
144	
145	pub fn process_file(path: &Path, functions: &mut Vec<FunctionInfo>, errors: &mut Vec<String>) {
146	    let source = match std::fs::read_to_string(path) {
147	        Ok(s) => s,
