1	use crate::ast::{extract_functions, parse_source_tree};
2	use crate::core::FunctionInfo;
3	use globset::{Glob, GlobSet, GlobSetBuilder};
4	use std::path::{Component, Path};
5	use std::process::Command;
6	use walkdir::WalkDir;
7	
8	const BUILTIN_EXCLUDED_DIRS: &[&str] = &[
9	    ".git",
10	    "target",
11	    "node_modules",
12	    "__pycache__",
13	    "vendor",
14	    "dist",
15	    ".next",
16	];
17	
18	pub fn is_builtin_excluded(path: &Path) -> bool {
19	    path.components().any(|c| {
20	        if let Component::Normal(name) = c {
21	            BUILTIN_EXCLUDED_DIRS.contains(&name.to_str().unwrap_or(""))
22	        } else {
23	            false
24	        }
25	    })
26	}
27	
28	fn git_check_ignore(path: &Path) -> Option<bool> {
29	    let abs = path.canonicalize().ok()?;
30	    let parent = abs.parent()?;
31	    let output = Command::new("git")
32	        .args([
33	            "-C",
34	            &parent.to_string_lossy(),
35	            "check-ignore",
36	            "--",
37	            &abs.to_string_lossy(),
38	        ])
39	        .output()
40	        .ok()?;
41	    Some(output.status.code() == Some(0))
42	}
43	
44	pub fn is_git_ignored(path: &Path) -> bool {
45	    git_check_ignore(path).unwrap_or(false)
46	}
47	
48	pub fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
49	    let mut builder = GlobSetBuilder::new();
50	    for pat in patterns {
51	        builder.add(Glob::new(pat)?);
52	    }
53	    builder.build()
54	}
55	
56	pub fn is_rust_file(path: &Path) -> bool {
57	    path.extension().and_then(|e| e.to_str()) == Some("rs")
58	}
59	
60	pub fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
61	    if exclude_set.is_empty() {
62	        return false;
63	    }
64	    exclude_set.is_match(path)
65	}
66	
67	pub fn collect_all_functions(
68	    paths: &[String],
69	    exclude_set: &GlobSet,
70	) -> (Vec<FunctionInfo>, Vec<String>) {
71	    let mut functions: Vec<FunctionInfo> = Vec::new();
72	    let mut errors: Vec<String> = Vec::new();
73	    for path_str in paths {
74	        let path = Path::new(path_str);
75	        if !path.exists() {
76	            errors.push(format!("path does not exist: {}", path_str));
77	        } else {
78	            collect_functions_from_path(path, exclude_set, &mut functions, &mut errors);
79	        }
80	    }
81	    (functions, errors)
82	}
83	
84	pub fn collect_functions_from_path(
85	    path: &Path,
86	    exclude_set: &GlobSet,
87	    functions: &mut Vec<FunctionInfo>,
88	    errors: &mut Vec<String>,
89	) {
90	    if path.is_file() {
91	        collect_from_single_file(path, exclude_set, functions, errors);
92	    } else {
93	        collect_from_directory(path, exclude_set, functions, errors);
94	    }
95	}
96	
97	pub fn should_scan_file(
98	    path: &Path,
99	    exclude_set: &GlobSet,
100	    git_ignored: &dyn Fn(&Path) -> bool,
101	) -> bool {
102	    !is_builtin_excluded(path)
103	        && is_rust_file(path)
104	        && !should_skip(path, exclude_set)
105	        && !git_ignored(path)
106	}
107	
108	pub fn collect_from_single_file(
109	    path: &Path,
110	    exclude_set: &GlobSet,
111	    functions: &mut Vec<FunctionInfo>,
112	    errors: &mut Vec<String>,
113	) {
114	    if should_scan_file(path, exclude_set, &is_git_ignored) {
115	        process_file(path, functions, errors);
116	    }
117	}
118	
119	fn process_entry(
120	    entry: Result<walkdir::DirEntry, walkdir::Error>,
121	    exclude_set: &GlobSet,
122	    functions: &mut Vec<FunctionInfo>,
123	    errors: &mut Vec<String>,
124	) {
125	    match entry {
126	        Ok(e)
127	            if e.file_type().is_file()
128	                && should_scan_file(e.path(), exclude_set, &is_git_ignored) =>
129	        {
130	            process_file(e.path(), functions, errors);
131	        }
132	        Ok(_) => {}
133	        Err(err) => errors.push(format!("walk error: {}", err)),
134	    }
135	}
136	
137	pub fn collect_from_directory(
138	    path: &Path,
139	    exclude_set: &GlobSet,
140	    functions: &mut Vec<FunctionInfo>,
141	    errors: &mut Vec<String>,
142	) {
143	    let walker = WalkDir::new(path)
144	        .sort_by_file_name()
145	        .into_iter()
146	        .filter_entry(|e| !e.file_type().is_dir() || !is_builtin_excluded(e.path()));
147	    for entry in walker {
148	        process_entry(entry, exclude_set, functions, errors);
149	    }
150	}
151	
152	pub fn process_file(path: &Path, functions: &mut Vec<FunctionInfo>, errors: &mut Vec<String>) {
153	    let source = match std::fs::read_to_string(path) {
154	        Ok(s) => s,
155	        Err(e) => {
156	            errors.push(format!("cannot read {}: {}", path.display(), e));
157	            return;
158	        }
159	    };
160	
161	    match parse_source_tree(&source) {
162	        Ok(tree) => {
163	            let file_str = path.to_string_lossy().to_string();
164	            extract_functions(tree.root_node(), &source, &file_str, functions);
165	        }
166	        Err(msg) => {
167	            errors.push(format!("{} in {}", msg, path.display()));
168	        }
169	    }
170	}
